"use client";

import type { JSX } from "react";
import { Button } from "@/components/ui/button";
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
import { Textarea } from "@/components/ui/textarea";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import { useForm } from "@tanstack/react-form";
import { useState } from "react";
import * as v from "valibot";
import { editProfile, type EditProfileErrorCode } from "./profile-edit.action";

const errorMessages: Record<EditProfileErrorCode, string> = {
  UNAUTHORIZED: "ログインが必要です",
  UPDATE_FAILED: "プロフィールの更新に失敗しました",
};

const nicknameSchema = v.pipe(
  v.string(),
  v.minLength(1, "ニックネームは必須です"),
  v.maxLength(50, "ニックネームは50文字以内で入力してください"),
);

const introduceSchema = v.pipe(
  v.string(),
  v.maxLength(500, "自己紹介は500文字以内で入力してください"),
);

const schema = v.object({
  nickname: nicknameSchema,
  introduce: introduceSchema,
});

interface Props {
  defaultNickname?: string;
  defaultIntroduce?: string;
  disabled?: boolean;
}

export function ProfileEditPresenter({
  defaultNickname = "",
  defaultIntroduce = "",
  disabled: disabledProperty = false,
}: Props): JSX.Element {
  const isHydrated = useIsHydrated();
  const disabled = disabledProperty || !isHydrated;
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const form = useForm({
    defaultValues: {
      nickname: defaultNickname,
      introduce: defaultIntroduce,
    },
    validators: {
      onBlur: schema,
    },
    onSubmit: async ({ value }) => {
      setSuccessMessage(null);
      setSubmitError(null);
      try {
        const response = await editProfile(value.nickname, value.introduce);
        if (response.success) {
          setSuccessMessage("プロフィールを保存しました");
        } else {
          setSubmitError(errorMessages[response.code]);
        }
      } catch {
        setSubmitError(errorMessages.UPDATE_FAILED);
      }
    },
  });

  // フォーム UI 部分は省略（Field, Input, Textarea, Button など）
}
```

**重要なパターン:**
- **@tanstack/react-form**: フォーム状態管理（バリデーション含む）
- **valibot**: スキーマベースのバリデーション
- **useIsHydrated**: ハイドレーション後のみ有効化（SSR対応）
- **disabled の合成**: `disabled = disabledProperty || !isHydrated`
- **エラーメッセージマッピング**: Result の code から表示文言を逆引き
- **送信状態管理**: `successMessage` / `submitError` で UI 表示制御

