  | { success: true; enrollments: Enrollment[] }
  | { success: false; code: GetEnrollmentsErrorCode };

export async function getEnrollments(): Promise<GetEnrollmentsResult> {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();
  if (!session) return { success: false, code: "UNAUTHORIZED" };

  const response = await fetch(
    `${process.env.API_URL}/v1/users/${session.user.id}/enrollments`,
    { headers: { Authorization: `Bearer ${session.access_token}` } },
  );

  if (response.status === 401) return { success: false, code: "UNAUTHORIZED" };
  if (!response.ok) return { success: false, code: "INTERNAL_ERROR" };

  const body = (await response.json()) as { enrollments: Enrollment[] };
  return { success: true, enrollments: body.enrollments };
}
```

メモ:
- API 仕様の `400 INPUT_VALIDATION_ERROR` は自分自身の userId しか送らないため発生しない想定。`!response.ok` で `INTERNAL_ERROR` に丸める（api-keys と同方針）。
- `404` は本 API では発生しない（受講ゼロ時も 200 + 空配列）。

### `handle-get-enrollments-result.server.ts`

`handle-list-api-keys-result.server.ts` 同型。

```ts
export function handleGetEnrollmentsResult(
  result: GetEnrollmentsResult,
): Enrollment[] {
  if (result.success) return result.enrollments;
  switch (result.code) {
    case "UNAUTHORIZED": redirect("/login"); break;
    case "INTERNAL_ERROR":
      throw new Error("受講中コース一覧の取得に失敗しました");
    default: {
      const exhaustiveCheck: never = result.code;
      throw new Error(`未対応のエラーコード: ${exhaustiveCheck}`);
    }
  }
}
```

### `enrollments-list.container.server.tsx`

```tsx
export async function EnrollmentsListContainer(): Promise<JSX.Element> {
  const enrollments = handleGetEnrollmentsResult(await getEnrollments());
  return <EnrollmentsListPresenter enrollments={enrollments} />;
}
```

### `enrollments-list.presenter.client.tsx`

- カードを 1 列で縦に並べる。`<ul>` + `<li>` + `<Link>` の素直な構造。
- 0 件時は「現在受講中の講座はありません」メッセージのみ。
- `disabled` prop は持たない。

```tsx
"use client";

interface Props { enrollments: Enrollment[] }

export function EnrollmentsListPresenter({ enrollments }: Props): JSX.Element {
  if (enrollments.length === 0) {
    return (
      <p className="text-muted-foreground text-sm">
        現在受講中の講座はありません
      </p>
    );
  }

  return (
    <ul className="flex flex-col gap-3">
      {enrollments.map((enrollment) => (
        <li key={enrollment.courseId}>
          <Link
            href={`/learning/${enrollment.courseId}` as Route}
            className={cn(
              "block rounded-md border border-border bg-card p-4",
              "transition-colors hover:border-primary/60",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/40",
            )}
          >
            <h2 className="text-foreground font-bold text-base line-clamp-2">
              {enrollment.title}
            </h2>
          </Link>
        </li>
      ))}
    </ul>
  );
}
```

メモ:
- カラーは `bg-card` `border-border` `text-foreground` `text-muted-foreground` などデザインシステムのもののみ。
- 中間変数を作らず className に直接記載（ui-component ルール）。
- typed routes 未生成のため `as Route` キャストで回避。

### `enrollments-list.skeleton.client.tsx`

Presenter とレイアウトを揃えた専用 Skeleton。CLS を避けるため列幅・余白を一致させる。

```tsx
const SKELETON_COUNT = 3;

export function EnrollmentsListSkeleton(): JSX.Element {
  return (
    <ul className="flex flex-col gap-3">
      {Array.from({ length: SKELETON_COUNT }, (_, index) => (
        // biome-ignore lint/suspicious/noArrayIndexKey: 静的個数のスケルトン
        <li
          key={index}
          className="rounded-md border border-border bg-card p-4"
        >
          <Skeleton className="h-5 w-4/5" />
        </li>
      ))}
    </ul>
  );
}
```

### `page.tsx`

`apps/web/app/(main)/settings/api-keys/page.tsx` 同型。

```tsx
export const metadata: Metadata = { title: "学習中" };

export default function LearningPage(): JSX.Element {
  return (
    <PageLayout title="学習中">
      <Suspense fallback={<EnrollmentsListSkeleton />}>
        <EnrollmentsListContainer />
      </Suspense>
    </PageLayout>
